sql:
SELECT DISTINCT customers.customer_name, customers.contact_email
FROM customers
JOIN instrument_assignments ON customers.customer_id = instrument_assignments.customer_id;

SELECT make
FROM instruments
WHERE status = 'active';

SELECT model_name 
FROM instrument_models 
WHERE model_id = (SELECT MIN(model_id) FROM instrument_models);

SELECT model_name, description 
FROM instrument_models 
WHERE model_id > 5;

